const assert = require("node:assert/strict");
const fs = require("node:fs");
const path = require("node:path");
const vm = require("node:vm");

const htmlPath = path.join(__dirname, "index.html");
assert.ok(fs.existsSync(htmlPath), "index.html should exist");

const html = fs.readFileSync(htmlPath, "utf8");
const scriptMatch = html.match(/<script id="pocketledger-app">([\s\S]*?)<\/script>/);
assert.ok(scriptMatch, "index.html should include the app script");

function createMemoryStorage() {
  const data = new Map();

  return {
    getItem(key) {
      return data.has(key) ? data.get(key) : null;
    },
    setItem(key, value) {
      data.set(key, String(value));
    },
    removeItem(key) {
      data.delete(key);
    },
  };
}

const fakeDocument = {
  addEventListener() {},
  querySelector() {
    return null;
  },
};

const fakeWindow = {
  crypto: {
    randomUUID() {
      return "test-random-id";
    },
  },
  document: fakeDocument,
  Intl,
  localStorage: createMemoryStorage(),
  navigator: { language: "en-US" },
};

const context = {
  console,
  crypto: fakeWindow.crypto,
  document: fakeDocument,
  Intl,
  localStorage: fakeWindow.localStorage,
  navigator: fakeWindow.navigator,
  window: fakeWindow,
};

vm.createContext(context);
vm.runInContext(scriptMatch[1], context, { filename: "index.html#pocketledger-app" });

function plain(value) {
  return JSON.parse(JSON.stringify(value));
}

const Ledger = context.window.PocketLedger;
assert.ok(Ledger, "PocketLedger API should be exposed for tests");

assert.equal(Ledger.parseAmountToCents("12.34"), 1234);
assert.equal(Ledger.parseAmountToCents("12,3"), 1230);
assert.equal(Ledger.parseAmountToCents(" 9 "), 900);
assert.throws(() => Ledger.parseAmountToCents("0"), /positive/i);
assert.throws(() => Ledger.parseAmountToCents("-4"), /positive/i);
assert.throws(() => Ledger.parseAmountToCents("2.999"), /two decimal/i);
assert.throws(() => Ledger.parseAmountToCents("coffee"), /valid amount/i);

const created = Ledger.createExpense(
  {
    amount: "7,50",
    category: " Food ",
    date: "2026-07-08",
    note: " Lunch ",
  },
  () => "expense-1",
  () => "2026-07-08T10:00:00.000Z",
);

assert.deepEqual(plain(created), {
  id: "expense-1",
  amountCents: 750,
  category: "Food",
  date: "2026-07-08",
  note: "Lunch",
  createdAt: "2026-07-08T10:00:00.000Z",
});

assert.throws(
  () =>
    Ledger.createExpense(
      { amount: "1", category: " ", date: "2026-07-08", note: "" },
      () => "id",
      () => "now",
    ),
  /category/i,
);

assert.throws(
  () =>
    Ledger.createExpense(
      { amount: "1", category: "Food", date: "08-07-2026", note: "" },
      () => "id",
      () => "now",
    ),
  /date/i,
);

const expenses = [
  { id: "a", amountCents: 1200, date: "2026-07-01", createdAt: "2026-07-01T08:00:00.000Z" },
  { id: "b", amountCents: 899, date: "2026-07-31", createdAt: "2026-07-31T08:00:00.000Z" },
  { id: "c", amountCents: 500, date: "2026-06-30", createdAt: "2026-06-30T08:00:00.000Z" },
];

assert.equal(Ledger.totalForMonth(expenses, "2026-07"), 2099);
assert.deepEqual(
  plain(Ledger.sortExpenses(expenses).map((expense) => expense.id)),
  ["b", "a", "c"],
);

const storage = createMemoryStorage();
Ledger.saveExpenses(storage, expenses);
assert.deepEqual(plain(Ledger.loadExpenses(storage)), expenses);

storage.setItem(Ledger.STORAGE_KEY, "not json");
assert.deepEqual(plain(Ledger.loadExpenses(storage)), []);

assert.equal(
  Ledger.expensesToCsv([
    {
      id: "x",
      amountCents: 1234,
      category: "Food, drinks",
      date: "2026-07-08",
      note: "Lunch\nwith tea",
      createdAt: "2026-07-08T10:00:00.000Z",
    },
    {
      id: "y",
      amountCents: 500,
      category: 'Travel "train"',
      date: "2026-07-09",
      note: "",
      createdAt: "2026-07-09T10:00:00.000Z",
    },
  ]),
  [
    "Date,Category,Amount,Note,Created At,ID",
    '2026-07-08,"Food, drinks",12.34,"Lunch\nwith tea",2026-07-08T10:00:00.000Z,x',
    '2026-07-09,"Travel ""train""",5.00,,2026-07-09T10:00:00.000Z,y',
  ].join("\r\n"),
);

assert.equal(Ledger.createCsvFilename(new Date(2026, 6, 8)), "pocketledger-expenses-2026-07-08.csv");

assert.equal(Ledger.formatCurrency(1234, "en-US"), "\u20ac12.34");

console.log("PocketLedger tests passed");

