  </main>

  <script id="pocketledger-app">
    (() => {
      const STORAGE_KEY = "pocketledger.expenses.v1";
      const DATE_PATTERN = /^\d{4}-\d{2}-\d{2}$/;
      const CSV_COLUMNS = ["Date", "Category", "Amount", "Note", "Created At", "ID"];

      function toLocalISODate(date = new Date()) {
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, "0");
        const day = String(date.getDate()).padStart(2, "0");
        return `${year}-${month}-${day}`;
      }

      function isValidISODate(value) {
        if (!DATE_PATTERN.test(String(value))) return false;
        const [year, month, day] = String(value).split("-").map(Number);
        const date = new Date(year, month - 1, day);
        return (
          date.getFullYear() === year &&
          date.getMonth() === month - 1 &&
          date.getDate() === day
        );
      }

      function parseAmountToCents(value) {
        const normalized = String(value).trim().replace(",", ".");
        const numericValue = Number(normalized);

        if (Number.isFinite(numericValue) && numericValue <= 0) {
          throw new Error("Amount must be positive.");
        }

        if (!/^\d+(\.\d+)?$/.test(normalized)) {
          throw new Error("Enter a valid amount.");
        }

        const [euros, cents = ""] = normalized.split(".");
        if (cents.length > 2) {
          throw new Error("Use at most two decimal places.");
        }

        return Number(euros) * 100 + Number(cents.padEnd(2, "0"));
      }

      function createExpense(input, idFactory = createId, nowFactory = () => new Date().toISOString()) {
        const category = String(input.category || "").trim();
        const date = String(input.date || "").trim();

        if (!category) {
          throw new Error("Category is required.");
        }

        if (!isValidISODate(date)) {
          throw new Error("Choose a valid date.");
        }

        return {
          id: idFactory(),
          amountCents: parseAmountToCents(input.amount),
          category,
          date,
          note: String(input.note || "").trim(),
          createdAt: nowFactory(),
        };
      }

      function createId() {
        if (crypto && typeof crypto.randomUUID === "function") {
          return crypto.randomUUID();
        }
        return `expense-${Date.now()}-${Math.random().toString(16).slice(2)}`;
      }

      function monthKey(date = toLocalISODate()) {
        return String(date).slice(0, 7);
      }

      function totalForMonth(expenses, targetMonthKey) {
        return expenses.reduce((total, expense) => {
          if (monthKey(expense.date) !== targetMonthKey) return total;
          return total + expense.amountCents;
        }, 0);
      }

      function sortExpenses(expenses) {
        return [...expenses].sort((a, b) => {
          const dateOrder = String(b.date || "").localeCompare(String(a.date || ""));
          if (dateOrder !== 0) return dateOrder;
          return String(b.createdAt || "").localeCompare(String(a.createdAt || ""));
        });
      }

      function escapeCsvCell(value) {
        const text = value == null ? "" : String(value);
        if (!/[",\r\n]/.test(text)) return text;
        return `"${text.replace(/"/g, '""')}"`;
      }

      function formatCsvAmount(cents) {
        return (Number(cents || 0) / 100).toFixed(2);
      }

      function expensesToCsv(expenses) {
        const rows = [
          CSV_COLUMNS,
          ...expenses.map((expense) => [
            expense.date || "",
            expense.category || "",
            formatCsvAmount(expense.amountCents),
            expense.note || "",
            expense.createdAt || "",
            expense.id || "",
          ]),
        ];

        return rows.map((row) => row.map(escapeCsvCell).join(",")).join("\r\n");
      }

      function createCsvFilename(date = new Date()) {
        return `pocketledger-expenses-${toLocalISODate(date)}.csv`;
      }

      function downloadExpensesCsv(expenses, documentObject = document) {
        const blob = new Blob([expensesToCsv(expenses)], { type: "text/csv;charset=utf-8" });
        const url = URL.createObjectURL(blob);
        const link = documentObject.createElement("a");
        link.href = url;
        link.download = createCsvFilename();
        link.style.display = "none";
        documentObject.body.append(link);
        link.click();
        link.remove();
        URL.revokeObjectURL(url);
      }

      function loadExpenses(storage = localStorage) {
        try {
          const raw = storage.getItem(STORAGE_KEY);
          if (!raw) return [];
          const parsed = JSON.parse(raw);
          return Array.isArray(parsed) ? parsed : [];
        } catch (error) {
          return [];
        }
      }

      function saveExpenses(storage = localStorage, expenses) {
        storage.setItem(STORAGE_KEY, JSON.stringify(expenses));
      }

      function formatCurrency(cents, locale = navigator.language) {
        return new Intl.NumberFormat(locale || undefined, {
          style: "currency",
          currency: "EUR",
          currencyDisplay: "symbol",
        }).format(cents / 100);
      }

      function formatDate(dateString, locale = navigator.language) {
        if (!isValidISODate(dateString)) return String(dateString || "");
        const [year, month, day] = dateString.split("-").map(Number);
        return new Intl.DateTimeFormat(locale || undefined, {
          day: "numeric",
          month: "short",
          year: "numeric",
        }).format(new Date(year, month - 1, day));
      }

      function formatMonthLabel(monthValue, locale = navigator.language) {
        const [year, month] = monthValue.split("-").map(Number);
        return new Intl.DateTimeFormat(locale || undefined, {
          month: "long",
          year: "numeric",
        }).format(new Date(year, month - 1, 1));
      }

      function init() {
        const elements = {
          amount: document.querySelector("#amount"),
          date: document.querySelector("#date"),
          form: document.querySelector("[data-expense-form]"),
          message: document.querySelector("[data-form-message]"),
          list: document.querySelector("[data-expense-list]"),
          empty: document.querySelector("[data-empty-state]"),
          count: document.querySelector("[data-expense-count]"),
          exportCsv: document.querySelector("[data-export-csv]"),
          total: document.querySelector("[data-total]"),
          monthSummary: document.querySelector("[data-month-summary]"),
          totalLabel: document.querySelector("#month-total-label"),
        };

        let expenses = sortExpenses(loadExpenses(localStorage));
        elements.date.value = toLocalISODate();

        elements.form.addEventListener("submit", (event) => {
          event.preventDefault();
          elements.message.textContent = "";

          const formData = new FormData(elements.form);

          try {
            const expense = createExpense({
              amount: formData.get("amount"),
              category: formData.get("category"),
              date: formData.get("date"),
              note: formData.get("note"),
            });
            const nextExpenses = sortExpenses([expense, ...expenses]);
            saveExpenses(localStorage, nextExpenses);
            expenses = nextExpenses;
            elements.form.reset();
            elements.date.value = toLocalISODate();
            elements.amount.focus();
            render();
          } catch (error) {
            elements.message.textContent = error.message || "Expense could not be saved.";
          }
        });

        elements.exportCsv.addEventListener("click", () => {
          if (expenses.length === 0) return;
          downloadExpensesCsv(expenses);
        });

        elements.list.addEventListener("click", (event) => {
          const button = event.target.closest("[data-delete-id]");
          if (!button) return;

          const nextExpenses = expenses.filter((expense) => expense.id !== button.dataset.deleteId);
          try {
            saveExpenses(localStorage, nextExpenses);
            expenses = nextExpenses;
            render();
          } catch (error) {
            elements.message.textContent = "Expense could not be deleted.";
          }
        });

        function render() {
          const currentMonth = monthKey();
          const currentMonthExpenses = expenses.filter((expense) => monthKey(expense.date) === currentMonth);
          elements.totalLabel.textContent = `${formatMonthLabel(currentMonth)} total`;
          elements.total.textContent = formatCurrency(totalForMonth(expenses, currentMonth));
          elements.monthSummary.textContent = summarizeCount(currentMonthExpenses.length, "this month");
          elements.count.textContent = summarizeCount(expenses.length, "total");
          elements.exportCsv.disabled = expenses.length === 0;
          renderExpenses(elements.list, expenses);
          elements.empty.hidden = expenses.length > 0;
        }

        render();
      }

      function summarizeCount(count, suffix) {
        const itemLabel = count === 1 ? "expense" : "expenses";
        return `${count} ${itemLabel} ${suffix}`;
      }

      function renderExpenses(list, expenses) {
        list.replaceChildren();

        for (const expense of expenses) {
          const item = document.createElement("li");
          item.className = "expense-row";

          const main = document.createElement("div");
          main.className = "expense-main";

          const category = document.createElement("div");
          category.className = "expense-category";
          category.textContent = expense.category || "Uncategorized";
          main.append(category);

          if (expense.note) {
            const note = document.createElement("p");
            note.className = "expense-note";
            note.textContent = expense.note;
            main.append(note);
          }

          const date = document.createElement("time");
          date.className = "expense-date";
          date.dateTime = expense.date || "";
          date.textContent = formatDate(expense.date);
          main.append(date);

          const amount = document.createElement("div");
          amount.className = "expense-amount";
          amount.textContent = formatCurrency(expense.amountCents || 0);

          const deleteButton = document.createElement("button");
          deleteButton.className = "icon-button";
          deleteButton.type = "button";
          deleteButton.dataset.deleteId = expense.id;
          deleteButton.setAttribute("aria-label", `Delete ${expense.category || "expense"}`);
          deleteButton.innerHTML = `
            <svg width="18" height="18" viewBox="0 0 24 24" aria-hidden="true">
              <path d="M9 4h6m-8 4h10m-9 0 .7 12h6.6L16 8" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"></path>
            </svg>
          `;

          item.append(main, amount, deleteButton);
          list.append(item);
        }
      }

      window.PocketLedger = {
        STORAGE_KEY,
        createCsvFilename,
        createExpense,
        expensesToCsv,
        formatCurrency,
        isValidISODate,
        loadExpenses,
        parseAmountToCents,
        saveExpenses,
        sortExpenses,
        totalForMonth,
      };

      document.addEventListener("DOMContentLoaded", init);
    })();
  </script>
</body>
